import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    query = "SELECT * FROM user_profiles WHERE 1=1"
    params = []

    if username:
        query += " AND username = %s"
        params.append(username)
    if email:
        query += " AND email = %s"
        params.append(email)
    if role:
        query += " AND role = %s"
        params.append(role)
    if status:
        query += " AND status = %s"
        params.append(status)

    try:
        connection = psycopg2.connect(
            dbname="your_db_name",
            user="your_db_user",
            password="your_db_password",
            host="your_db_host",
            port="your_db_port"
        )
        cursor = connection.cursor()
        cursor.execute(query, params)
        results = cursor.fetchall()
        cursor.close()
        connection.close()
        return results
    except psycopg2.Error as e:
        print(f"Database error: {e}")
        return None

